#!/usr/bin/env node
// Minimal CLI: `md3 alias <component...> --dir <dir>` writes a re-export file
// per component that also imports its required css (see css-manifest.json,
// generated by scripts/build-css-manifest.mjs), so consumers don't have to
// know which stylesheets a component needs. tokens.css/ripple.css are global
// setup and are not written here — see the reminder printed below.
import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const pkgRoot = join(dirname(fileURLToPath(import.meta.url)), "..");
const manifest = JSON.parse(readFileSync(join(pkgRoot, "dist/css-manifest.json"), "utf8"));
const pkgName = JSON.parse(readFileSync(join(pkgRoot, "package.json"), "utf8")).name;

function usage() {
  console.error("Usage: md3 alias <component> [<component>...] --dir <dir>");
  console.error(`Available components: ${Object.keys(manifest).toSorted().join(", ")}`);
  process.exit(1);
}

function alias(components, dir) {
  mkdirSync(dir, { recursive: true });

  for (const name of components) {
    const cssFiles = manifest[name];
    if (!cssFiles) {
      console.error(`Unknown component "${name}".`);
      console.error(`Available components: ${Object.keys(manifest).toSorted().join(", ")}`);
      process.exit(1);
    }

    const cssImports = cssFiles.map((css) => `import "${pkgName}/${css}.css";\n`).join("");
    const file = join(dir, `${name}.tsx`);
    writeFileSync(file, `${cssImports}\nexport * from "${pkgName}/${name}";\n`);
    console.log(`wrote ${file}`);
  }

  console.log(
    `\nRemember to import "${pkgName}/tokens.css" (and "${pkgName}/ripple.css" for pressable components) once globally — not written into these files.`,
  );
}

const [command, ...rest] = process.argv.slice(2);
if (command !== "alias") usage();

const dirFlagIndex = rest.indexOf("--dir");
if (dirFlagIndex === -1 || !rest[dirFlagIndex + 1]) usage();

const dir = rest[dirFlagIndex + 1];
const components = [...rest.slice(0, dirFlagIndex), ...rest.slice(dirFlagIndex + 2)];
if (components.length === 0) usage();

alias(components, dir);
